function validateProject(project){const required = ['name','description','url'];const missing = required.filter(field => !project[field]);if(missing.length > 0){console.warn(`Project missing required fields:${missing.join(',')}`,project);return false;}try{new URL(project.url);}catch(error){console.warn(`Project has invalid URL:${project.url}`,project);return false;}return true;}async function loadProjects(){try{const response = await fetch('projects.json');if(!response.ok){throw new Error(`HTTP error:${response.status}`);}const data = await response.json();if(!data || typeof data !== 'object'){throw new Error('Invalid data format:expected object');}if(!Array.isArray(data.projects)){throw new Error('Invalid data format:projects must be an array');}const validProjects = data.projects.filter(validateProject);if(validProjects.length < data.projects.length){console.warn(`Filtered out ${data.projects.length - validProjects.length}invalid projects`);}return{projects:validProjects,lastUpdated:data.lastUpdated};}catch(error){console.error('Failed to load projects:',error);displayErrorMessage('Unable to load projects. Please try again later.');return{projects:[]};}}function displayErrorMessage(message){const container = document.getElementById('project-grid');if(container){container.innerHTML = ` <div class="error-message" role="alert"> <p>${message}</p> </div> `;}}function isValidNavigationURL(url){try{const urlObject = new URL(url);return urlObject.protocol === 'http:' || urlObject.protocol === 'https:';}catch(error){return false;}}function safeNavigate(url,cardElement){if(!isValidNavigationURL(url)){console.error('Navigation error:Invalid URL',url);displayNavigationError(cardElement,'Invalid URL');return false;}try{window.open(url,'_blank','noopener,noreferrer');return true;}catch(error){console.error('Navigation error:',error,'URL:',url);displayNavigationError(cardElement,'Failed to open link');return false;}}function displayNavigationError(cardElement,errorMessage){cardElement.classList.add('error');let errorElement = cardElement.querySelector('.project-card-error');if(!errorElement){errorElement = document.createElement('div');errorElement.className = 'project-card-error';errorElement.setAttribute('role','alert');cardElement.appendChild(errorElement);}errorElement.textContent = `⚠ ${errorMessage}`;setTimeout(()=>{cardElement.classList.remove('error');if(errorElement && errorElement.parentNode){errorElement.remove();}},5000);}function renderProjectCard(project){const card = document.createElement('div');card.className = 'project-card';card.setAttribute('tabindex','0');card.setAttribute('role','listitem');card.setAttribute('aria-label',`Project:${project.name}`);const descriptionId = `project-desc-${project.name.toLowerCase().replace(/\s+/g,'-')}`;if(project.image){const imageContainer = document.createElement('div');imageContainer.className = 'project-card-image';const img = document.createElement('img');img.src = project.image;img.alt = `${project.name}preview`;img.loading = 'lazy';img.onerror = function(){imageContainer.style.display = 'none';};imageContainer.appendChild(img);card.appendChild(imageContainer);}const title = document.createElement('h3');title.textContent = project.name;card.appendChild(title);const description = document.createElement('p');description.textContent = project.description;description.id = descriptionId;card.appendChild(description);card.setAttribute('aria-describedby',descriptionId);const linksContainer = document.createElement('div');linksContainer.className = 'project-card-links';if(project.liveDemo){const liveDemoLink = document.createElement('a');liveDemoLink.href = project.liveDemo;liveDemoLink.textContent = '🚀 Live Demo';liveDemoLink.className = 'project-link-demo';liveDemoLink.setAttribute('target','_blank');liveDemoLink.setAttribute('rel','noopener noreferrer');liveDemoLink.setAttribute('aria-label',`View live demo of ${project.name}`);liveDemoLink.addEventListener('click',(e)=>{e.stopPropagation();e.preventDefault();safeNavigate(project.liveDemo,card);});linksContainer.appendChild(liveDemoLink);}const repoLink = document.createElement('a');repoLink.href = project.url;repoLink.textContent = '📦 Repository';repoLink.className = 'project-link-repo';repoLink.setAttribute('target','_blank');repoLink.setAttribute('rel','noopener noreferrer');repoLink.setAttribute('aria-label',`View ${project.name}repository`);repoLink.addEventListener('click',(e)=>{e.stopPropagation();e.preventDefault();safeNavigate(project.url,card);});linksContainer.appendChild(repoLink);card.appendChild(linksContainer);if(project.tags && Array.isArray(project.tags)&& project.tags.length > 0){const tagsContainer = document.createElement('div');tagsContainer.className = 'project-card-tags';project.tags.forEach(tag =>{const tagElement = document.createElement('span');tagElement.className = 'project-card-tag';tagElement.textContent = tag;tagsContainer.appendChild(tagElement);});card.appendChild(tagsContainer);}card.addEventListener('click',()=>{const targetUrl = project.liveDemo || project.url;safeNavigate(targetUrl,card);});card.addEventListener('keydown',(e)=>{if(e.key === 'Enter' || e.key === ' '){e.preventDefault();const targetUrl = project.liveDemo || project.url;safeNavigate(targetUrl,card);}});return card;}function renderAllProjects(projects){const container = document.getElementById('project-grid');if(!container){console.error('Project grid container not found');return;}container.innerHTML = '';projects.forEach((project,index)=>{const card = renderProjectCard(project);card.style.animationDelay = `${index * 0.1}s`;container.appendChild(card);});}async function initShowroom(){try{const data = await loadProjects();if(data.projects && data.projects.length > 0){renderAllProjects(data.projects);}else{displayErrorMessage('No projects available to display.');}}catch(error){console.error('Failed to initialize showroom:',error);displayErrorMessage('Failed to initialize the showroom. Please refresh the page.');}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',initShowroom);}else{initShowroom();}